const payload = $json;
const action = payload.action;
const pr = payload.pull_request || {};
const repo = payload.repository || {};

const merged = pr.merged === true;
const branch = (pr.head || {}).ref || '';
const actor = (pr.merged_by || pr.user || {}).login || 'unknown';
const prNumber = pr.number || null;
const prTitle = pr.title || '';
const prBody = pr.body || '';
const repoName = repo.name || '';
const repoFullName = repo.full_name || repoName;
const prUrl = pr.html_url || '';
const sha = (pr.merge_commit_sha || '').slice(0, 7);

// Fuentes donde puede venir la referencia a Trello
const searchableText = [
  branch,
  prTitle,
  prBody,
  prUrl
].filter(Boolean).join(' ');

// Soporta:
// 1. trello-CARDID
// 2. trello_CARDID
// 3. trello/CARDID
// 4. URLs tipo https://trello.com/c/CARDID/slug
const trelloPatterns = [
  /trello[-_\/]([a-zA-Z0-9]+)/i,
  /trello\.com\/c\/([a-zA-Z0-9]+)/i
];

let trelloCardId = null;
for (const pattern of trelloPatterns) {
  const match = searchableText.match(pattern);
  if (match && match[1]) {
    trelloCardId = match[1];
    break;
  }
}

const correlationId = `sync-pr-${repoName || 'repo'}-${prNumber || 'unknown'}-${Date.now()}`;

if (action !== 'closed' || !merged) {
  return [{
    json: {
      skip: true,
      reason: `PR action=${action}, merged=${merged}`,
      action,
      merged,
      repo: repoName,
      repo_full_name: repoFullName,
      pr_number: prNumber,
      pr_title: prTitle,
      branch,
      actor,
      pr_url: prUrl,
      sha,
      trello_card_id: trelloCardId,
      correlation_id: correlationId
    }
  }];
}

return [{
  json: {
    skip: false,
    action,
    merged,
    pr_number: prNumber,
    pr_title: prTitle,
    branch,
    actor,
    trello_card_id: trelloCardId,
    repo: repoName,
    repo_full_name: repoFullName,
    pr_url: prUrl,
    sha,
    correlation_id: correlationId,
    sync_source: 'github_pull_request',
    sync_status: trelloCardId ? 'ready_with_trello_card' : 'ready_without_trello_card'
  }
}];

