const ctx = $('Verify Merged & Extract Context').item.json;

return [{
  json: {
    ...ctx,
    trello_action: 'archived_and_commented',
    sync_status: 'trello_done'
  }
}];

const ctx = $json;
const hasTrello = !!ctx.trello_card_id;
const trelloDone = ctx.sync_status === 'trello_done';

const trelloLine = hasTrello
  ? (trelloDone
      ? `✅ Tarjeta Trello \`${ctx.trello_card_id}\` archivada y comentada.`
      : `ℹ️ Tarjeta Trello detectada: \`${ctx.trello_card_id}\`.`)
  : `⚠️ No se encontró referencia a Trello en el branch, título, descripción o URL del PR.`;

const content = [
  `🔀 **PR Mergeado** en \`${ctx.repo_full_name || ctx.repo}\``,
  `📌 **PR #${ctx.pr_number}:** ${ctx.pr_title}`,
  `🌿 Branch: \`${ctx.branch}\``,
  `👤 Autor/Mergeado por: **${ctx.actor}**`,
  ctx.sha ? `🔗 Commit: \`${ctx.sha}\`` : null,
  ctx.pr_url ? `🌐 PR: ${ctx.pr_url}` : null,
  trelloLine,
  `🧾 Correlation ID: \`${ctx.correlation_id}\``,
  ``,
  `🧑‍💻 **Testers:** Por favor verifiquen la build correspondiente.`
].filter(Boolean).join('\n');

return [{
  json: {
    ...ctx,
    content,
    discord_ready: true
  }
}];

const ctx = $('Build Discord Notification').item.json || {};

return [{
  json: {
    correlation_id: ctx.correlation_id,
    agent_role: 'Sync Bidireccional',
    decision_type: 'github_trello_sync',
    input_summary: `PR #${ctx.pr_number || '-'} merged in ${ctx.repo_full_name || ctx.repo || 'unknown repo'}`,
    context_used: {
      sync_source: ctx.sync_source || 'github_pull_request',
      repo: ctx.repo,
      repo_full_name: ctx.repo_full_name,
      pr_number: ctx.pr_number,
      pr_title: ctx.pr_title,
      branch: ctx.branch,
      actor: ctx.actor,
      sha: ctx.sha,
      pr_url: ctx.pr_url,
      trello_card_id: ctx.trello_card_id || null
    },
    evidence: {
      trello_action: ctx.trello_action || 'not_available',
      discord_queued: true
    },
    decision: {
      sync_status: ctx.sync_status || 'discord_queued',
      trello_action: ctx.trello_action || 'not_available',
      discord_notified: true
    },
    recommendation: ctx.trello_card_id
      ? 'Validar build y QA posterior al merge; Trello fue actualizado automáticamente.'
      : 'Validar build y crear vínculo Trello si este PR pertenece a una tarea del tablero.',
    confidence: 0.9,
    risk_level: ctx.trello_card_id ? 'low' : 'medium',
    requires_human_approval: false
  }
}];
